const url = String($json.product_url ?? '').trim();
const targetPrice = Number($json.price_threshold ?? 0);

const asin =
  url.match(/\/dp\/([A-Z0-9]{10})/)?.[1] ??
  url.match(/\/gp\/product\/([A-Z0-9]{10})/)?.[1] ??
  url.match(/\/gp\/aw\/d\/([A-Z0-9]{10})/)?.[1] ??
  url.match(/\/product\/([A-Z0-9]{10})/)?.[1] ??
  url.match(/\b([B][0-9A-Z]{9})\b/)?.[1] ??
  null;
const domain = url.match(/amazon\.([a-z.]+?)\//)?.[1] ?? 'com';

if (!asin) {
  throw new Error(`Could not extract ASIN from URL: "${url}". Use a standard Amazon product URL containing /dp/ASIN.`);
}

return [{ json: { asin, domain, productUrl: url, targetPrice } }];

const product = $json.data ?? $json;
const row = $('Read watchlist').item.json;
const parsed = $('Parse URL').item.json;

const currentPrice = Number(product.price?.value ?? product.price ?? product.priceValue ?? 0);
const targetPrice = Number(parsed.targetPrice);

const lastAlertedRaw = String(row.last_alerted_price ?? '').trim();
const lastAlertedPrice = lastAlertedRaw === '' ? null : Number(lastAlertedRaw);

const shouldAlert =
  currentPrice > 0 &&
  targetPrice > 0 &&
  currentPrice <= targetPrice &&
  (lastAlertedPrice === null || currentPrice < lastAlertedPrice);

return [{
  json: {
    productUrl: parsed.productUrl,
    asin: parsed.asin,
    title: product.title ?? null,
    currentPrice,
    targetPrice,
    lastAlertedPrice,
    shouldAlert,
  },
}];

